#!/usr/bin/env node
// Generates the package-manager manifests that WRAP the published `loomctl` npm package — a Homebrew
// formula, a Scoop manifest, and a winget multi-file manifest — into ./packaging. See
// packaging/README.md + docs/packaging-submission.md ("Submission runbook").
//
// Single source of truth = the root package.json version (the same number build-npm-package.mjs reads
// for the published `loomctl` package.json). Run this AFTER `npm version` so a release bumps the
// manifests in lockstep with the package; commit the regenerated files.
//
// The sha256 hashes of the published artifacts are NOT known until the tarball/zip are published, so
// they default to a loud placeholder. Pass them on a re-run to fill them in for submission:
//   node scripts/generate-manifests.mjs --sha-npm=<sha256 of loomctl-X.Y.Z.tgz from npm> \
//                                       --sha-win-zip=<sha256 of loomctl-X.Y.Z-win.zip>
// (compute with: shasum -a 256 <file>  /  Get-FileHash -Algorithm SHA256 <file>). See the runbook for
// how to fetch the published npm tarball + its integrity hash.
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const args = process.argv.slice(2);
const flag = (name) => {
  const hit = args.find((a) => a.startsWith(`--${name}=`));
  return hit ? hit.slice(name.length + 3) : undefined;
};
const log = (m) => console.log(`[manifests] ${m}`);

// Canonical metadata = the root package.json (same single source of truth as build-npm-package.mjs).
const rootPkg = JSON.parse(fs.readFileSync(path.join(repoRoot, "package.json"), "utf8"));
const version = rootPkg.version;
const description = rootPkg.description;
const license = rootPkg.license ?? "MIT";
// Homebrew's `brew audit --strict` requires desc <= 80 chars and rejects em dashes / leading articles,
// so the full root description won't pass. Use a trimmed, audit-safe variant for the formula only.
const HOMEBREW_DESC = "Local-first AI project workspace for Claude Code, Obsidian, and tasks";

// Published shape (set in scripts/build-npm-package.mjs): npm name `loomctl`, bin `loom`.
const PKG = "loomctl";
const BIN = "loom";
const HOMEPAGE = "https://github.com/DanielC000/loom";
const REPO = "https://github.com/DanielC000/loom";
const PUBLISHER = "Loom";
const AUTHOR = "DanielC000";

// The artifacts the manifests point at. brew + scoop wrap the *npm registry* tarball; winget has no
// way to run npm, so it wraps a GitHub-Release **zip** of the assembled bundle (see runbook).
const NPM_TARBALL = `https://registry.npmjs.org/${PKG}/-/${PKG}-${version}.tgz`;
const WIN_ZIP = `${REPO}/releases/download/v${version}/${PKG}-${version}-win.zip`;

const SHA_PLACEHOLDER = "REPLACE_WITH_SHA256_OF_PUBLISHED_ARTIFACT";
const shaNpm = flag("sha-npm") ?? SHA_PLACEHOLDER;
const shaWinZip = flag("sha-win-zip") ?? SHA_PLACEHOLDER;

const outDir = path.join(repoRoot, "packaging");
const write = (rel, contents) => {
  const abs = path.join(outDir, rel);
  fs.mkdirSync(path.dirname(abs), { recursive: true });
  fs.writeFileSync(abs, contents);
  log(`wrote ${path.relative(repoRoot, abs).split(path.sep).join("/")}`);
};

// ── Homebrew formula ────────────────────────────────────────────────────────────────────────────
// Conventional Node-CLI-from-npm formula: pull the published npm tarball, install with std_npm_args
// (Homebrew's Language::Node helper installs into libexec + brings in node's bundled npm), then
// symlink the produced bins. node@22 is a hard dep (Loom needs Node 22+). Native deps
// (better-sqlite3, node-pty) install via their npm-fetched prebuilt binaries during `npm install`.
const homebrew = `require "language/node"

# Homebrew formula for the Loom CLI (published on npm as "${PKG}", exposes the "${BIN}" command).
# GENERATED by scripts/generate-manifests.mjs from the root package.json version — do not hand-edit
# the version/url; re-run the generator after \`npm version\` and fill the sha256 (see the runbook).
class Loomctl < Formula
  desc "${HOMEBREW_DESC}"
  homepage "${HOMEPAGE}"
  url "${NPM_TARBALL}"
  sha256 "${shaNpm}"
  license "${license}"

  depends_on "node@22"

  def install
    system "npm", "install", *std_npm_args
    bin.install_symlink Dir["#{libexec}/bin/*"]
  end

  test do
    assert_match "v#{version}", shell_output("#{bin}/${BIN} --version")
  end
end
`;
write("homebrew/loomctl.rb", homebrew);

// ── Scoop manifest ──────────────────────────────────────────────────────────────────────────────
// Scoop has no npm step, so we download the npm tarball (it extracts to package/), depend on the
// Scoop "nodejs-lts" package, run `npm install --omit=dev` in the dir during install to fetch
// runtime deps (incl. the native prebuilt binaries), and synthesize a loom.cmd shim that calls node
// on bin/loom.mjs. autoupdate templates the npm tarball URL so a bumped version re-resolves the hash.
const scoop = {
  version,
  description,
  homepage: HOMEPAGE,
  license,
  depends: "nodejs-lts",
  url: NPM_TARBALL,
  hash: `sha256:${shaNpm}`,
  extract_dir: "package",
  installer: {
    script: [
      "Push-Location \"$dir\"",
      "& npm install --omit=dev --no-audit --no-fund --no-package-lock --loglevel=error",
      "Pop-Location",
      "# Shim: `loom` -> node bin\\loom.mjs (Scoop shims the .cmd as `loom`).",
      "Set-Content -LiteralPath \"$dir\\loom.cmd\" -Encoding Ascii -Value '@node \"%~dp0bin\\loom.mjs\" %*'",
    ],
  },
  uninstaller: {
    script: ["if (Test-Path \"$dir\\loom.cmd\") { Remove-Item -Force \"$dir\\loom.cmd\" }"],
  },
  bin: "loom.cmd",
  checkver: {
    url: "https://registry.npmjs.org/loomctl/latest",
    jsonpath: "$.version",
  },
  // No autoupdate.hash extraction: npm's $.dist.integrity is SRI sha512-base64, which won't match the
  // sha256 hex `hash` field. Omitting it makes Scoop download the new tarball and compute the hash.
  autoupdate: {
    url: `https://registry.npmjs.org/${PKG}/-/${PKG}-$version.tgz`,
  },
};
write("scoop/loomctl.json", JSON.stringify(scoop, null, 4) + "\n");

// ── winget multi-file manifest ────────────────────────────────────────────────────────────────────
// winget cannot run npm, so it wraps a GitHub-Release **zip** of the assembled bundle (the owner must
// produce loomctl-X.Y.Z-win.zip in the release — see the runbook; the release today ships only the
// .tgz). InstallerType: zip with a nested `portable` **loom.exe** — winget's portable type accepts ONLY
// executables (a .cmd/.bat is rejected by `winget validate`), so the zip must bundle a small loom.exe
// launcher (Node SEA / thin stub wrapping bin/loom.mjs — a deferred OWNER prerequisite, see the runbook).
// Node 22+ must be on PATH unless the launcher bundles its own Node. Multi-file layout (schema 1.6.0):
// version + installer + default-locale manifests, PackageIdentifier "${PUBLISHER}.Loomctl".
const PKG_ID = `${PUBLISHER}.Loomctl`;
const SCHEMA = "1.6.0";
const yamlHeader = (type) =>
  `# yaml-language-server: $schema=https://aka.ms/winget-manifest.${type}.${SCHEMA}.schema.json\n`;

const wingetVersion = `${yamlHeader("version")}# GENERATED by scripts/generate-manifests.mjs — version from root package.json.
PackageIdentifier: ${PKG_ID}
PackageVersion: ${version}
DefaultLocale: en-US
ManifestType: version
ManifestVersion: ${SCHEMA}
`;
write(`winget/${PKG_ID}.yaml`, wingetVersion);

const wingetInstaller = `${yamlHeader("installer")}# GENERATED by scripts/generate-manifests.mjs — version + InstallerUrl from root package.json.
# NOTE: winget has no npm step. This wraps a GitHub-Release zip of the assembled bundle; Node 22+ must
# already be on PATH (winget cannot declare an npm/node dependency). See docs/packaging-submission.md.
PackageIdentifier: ${PKG_ID}
PackageVersion: ${version}
MinimumOSVersion: 10.0.0.0
InstallerType: zip
NestedInstallerType: portable
NestedInstallerFiles:
  - RelativeFilePath: ${PKG}-${version}-win\\loom.exe
    PortableCommandAlias: ${BIN}
Installers:
  - Architecture: x64
    InstallerUrl: ${WIN_ZIP}
    InstallerSha256: ${shaWinZip}
ManifestType: installer
ManifestVersion: ${SCHEMA}
`;
write(`winget/${PKG_ID}.installer.yaml`, wingetInstaller);

const wingetLocale = `${yamlHeader("defaultLocale")}# GENERATED by scripts/generate-manifests.mjs — version from root package.json.
PackageIdentifier: ${PKG_ID}
PackageVersion: ${version}
PackageLocale: en-US
Publisher: ${PUBLISHER}
PublisherUrl: ${REPO}
PublisherSupportUrl: ${REPO}/issues
Author: ${AUTHOR}
PackageName: Loom
PackageUrl: ${HOMEPAGE}
License: ${license}
LicenseUrl: ${REPO}/blob/main/LICENSE
ShortDescription: ${description}
Description: ${description}
Tags:
  - ai
  - claude
  - cli
  - developer-tools
  - obsidian
ManifestType: defaultLocale
ManifestVersion: ${SCHEMA}
`;
write(`winget/${PKG_ID}.locale.en-US.yaml`, wingetLocale);

log(`done — ${PKG}@${version} (sha256 ${shaNpm === SHA_PLACEHOLDER ? "PLACEHOLDER — fill before submission" : "filled"})`);
